import json

# Read and validate JSON
with open('/workspace/implementors.json', 'r') as f:
    data = json.load(f)

print(f"Total implementors found: {len(data)}")
print(f"\nBreakdown by repository:")

repos = {}
for item in data:
    repo = item['repo']
    if repo not in repos:
        repos[repo] = 0
    repos[repo] += 1

for repo, count in sorted(repos.items()):
    print(f"  {repo}: {count}")

print(f"\nBreakdown by top API groups:")
